  1→use anyhow::{Context, Result};
  2→use chrono::{DateTime, Utc};
  3→use serde::{Deserialize, Serialize};
  4→use std::fs;
  5→use std::io::Write;
  6→use tracing::warn;
  7→
  8→#[derive(Debug, Clone, Serialize, Deserialize)]
  9→pub struct StateEntry {
 10→    pub phase: String,
 11→    /// Sub-phase number if this is a sub-phase entry (e.g., "05.1")
 12→    #[serde(default, skip_serializing_if = "Option::is_none")]
 13→    pub sub_phase: Option<String>,
 14→    pub iteration: u32,
 15→    pub status: String,
 16→    pub timestamp: DateTime<Utc>,
 17→}
 18→
 19→impl StateEntry {
 20→    /// Check if this is a sub-phase entry.
 21→    pub fn is_sub_phase(&self) -> bool {
 22→        self.sub_phase.is_some()
 23→    }
 24→
 25→    /// Get the full phase/sub-phase identifier.
 26→    pub fn full_phase_id(&self) -> String {
 27→        self.sub_phase.clone().unwrap_or_else(|| self.phase.clone())
 28→    }
 29→
 30→    /// Get the parent phase number for sub-phase entries.
 31→    pub fn parent_phase(&self) -> &str {
 32→        &self.phase
 33→    }
 34→}
 35→
 36→pub struct StateManager {
 37→    state_file: std::path::PathBuf,
 38→}
 39→
 40→impl StateManager {
 41→    pub fn new(state_file: std::path::PathBuf) -> Self {
 42→        Self { state_file }
 43→    }
 44→
 45→    /// Save a phase state entry (legacy format, backward compatible).
 46→    pub fn save(&self, phase: &str, iteration: u32, status: &str) -> Result<()> {
 47→        let entry = format!(
 48→            "{}|{}|{}|{}\n",
 49→            phase,
 50→            iteration,
 51→            status,
 52→            Utc::now().to_rfc3339()
 53→        );
 54→
 55→        fs::OpenOptions::new()
 56→            .create(true)
 57→            .append(true)
 58→            .open(&self.state_file)
 59→            .context("Failed to open state file")?
 60→            .write_all(entry.as_bytes())
 61→            .context("Failed to write state entry")?;
 62→
 63→        Ok(())
 64→    }
 65→
 66→    /// Save a sub-phase state entry with parent phase reference.
 67→    /// Format: phase|sub_phase|iteration|status|timestamp
 68→    pub fn save_sub_phase(
 69→        &self,
 70→        parent_phase: &str,
 71→        sub_phase: &str,
 72→        iteration: u32,
 73→        status: &str,
 74→    ) -> Result<()> {
 75→        let entry = format!(
 76→            "{}|{}|{}|{}|{}\n",
 77→            parent_phase,
 78→            sub_phase,
 79→            iteration,
 80→            status,
 81→            Utc::now().to_rfc3339()
 82→        );
 83→
 84→        fs::OpenOptions::new()
 85→            .create(true)
 86→            .append(true)
 87→            .open(&self.state_file)
 88→            .context("Failed to open state file")?
 89→            .write_all(entry.as_bytes())
 90→            .context("Failed to write sub-phase state entry")?;
 91→
 92→        Ok(())
 93→    }
 94→
 95→    /// Get the last completed top-level phase (not sub-phases).
 96→    pub fn get_last_completed_phase(&self) -> Option<String> {
 97→        if !self.state_file.exists() {
 98→            return None;
 99→        }
100→
101→        let content = fs::read_to_string(&self.state_file).ok()?;
102→
103→        content
104→            .lines()
105→            .rfind(|line| {
106→                let parts: Vec<&str> = line.split('|').collect();
107→                // Old format has 4 parts, new sub-phase format has 5 parts
108→                // Only consider old format (top-level phases) for this query
109→                parts.len() == 4 && line.contains("|completed|")
110→            })
111→            .and_then(|line| line.split('|').next())
112→            .map(|s| s.to_string())
113→    }
114→
115→    /// Get the last completed phase or sub-phase.
116→    pub fn get_last_completed_any(&self) -> Option<String> {
117→        if !self.state_file.exists() {
118→            return None;
119→        }
120→
121→        let content = fs::read_to_string(&self.state_file).ok()?;
122→
123→        content
124→            .lines()
125→            .rfind(|line| line.contains("|completed|"))
126→            .and_then(|line| {
127→                let parts: Vec<&str> = line.split('|').collect();
128→                if parts.len() == 5 {
129→                    // Sub-phase format: phase|sub_phase|iteration|status|timestamp
130→                    Some(parts[1].to_string()) // Return sub-phase number
131→                } else if parts.len() >= 4 {
132→                    // Old format: phase|iteration|status|timestamp
133→                    Some(parts[0].to_string())
134→                } else {
135→                    None
136→                }
137→            })
138→    }
139→
140→    /// Get all state entries including sub-phase entries.
141→    ///
142→    /// Lines that cannot be fully parsed (e.g. corrupt or partial writes) are
143→    /// silently skipped with a warning rather than being returned as bogus
144→    /// entries with iteration == 0.
145→    pub fn get_entries(&self) -> Result<Vec<StateEntry>> {
146→        if !self.state_file.exists() {
147→            return Ok(Vec::new());
148→        }
149→
150→        let content = fs::read_to_string(&self.state_file).context("Failed to read state file")?;
151→
152→        let entries: Vec<StateEntry> = content
153→            .lines()
154→            .filter_map(|line| {
155→                let parts: Vec<&str> = line.split('|').collect();
156→                if parts.len() == 5 {
157→                    // New sub-phase format: phase|sub_phase|iteration|status|timestamp
158→                    let iteration = match parts[2].parse::<u32>() {
159→                        Ok(n) => n,
160→                        Err(_) => {
161→                            warn!(
162→                                "state: skipping malformed sub-phase line (bad iteration): {line}"
163→                            );
164→                            return None;
165→                        }
166→                    };
167→                    Some(StateEntry {
168→                        phase: parts[0].to_string(),
169→                        sub_phase: Some(parts[1].to_string()),
170→                        iteration,
171→                        status: parts[3].to_string(),
172→                        timestamp: DateTime::parse_from_rfc3339(parts[4])
173→                            .ok()?
174→                            .with_timezone(&Utc),
175→                    })
176→                } else if parts.len() >= 4 {
177→                    // Old format: phase|iteration|status|timestamp
178→                    let iteration = match parts[1].parse::<u32>() {
179→                        Ok(n) => n,
180→                        Err(_) => {
181→                            warn!("state: skipping malformed entry line (bad iteration): {line}");
182→                            return None;
183→                        }
184→                    };
185→                    Some(StateEntry {
186→                        phase: parts[0].to_string(),
187→                        sub_phase: None,
188→                        iteration,
189→                        status: parts[2].to_string(),
190→                        timestamp: DateTime::parse_from_rfc3339(parts[3])
191→                            .ok()?
192→                            .with_timezone(&Utc),
193→                    })
194→                } else {
195→                    None
196→                }
197→            })
198→            .collect();
199→
200→        Ok(entries)
201→    }
202→
203→    /// Get entries for a specific phase including its sub-phases.
204→    pub fn get_phase_entries(&self, phase: &str) -> Result<Vec<StateEntry>> {
205→        let entries = self.get_entries()?;
206→        Ok(entries.into_iter().filter(|e| e.phase == phase).collect())
207→    }
208→
209→    /// Get entries for a specific sub-phase.
210→    pub fn get_sub_phase_entries(&self, sub_phase: &str) -> Result<Vec<StateEntry>> {
211→        let entries = self.get_entries()?;
212→        Ok(entries
213→            .into_iter()
214→            .filter(|e| e.sub_phase.as_deref() == Some(sub_phase))
215→            .collect())
216→    }
217→
218→    /// Check if a phase has any sub-phase entries.
219→    pub fn has_sub_phase_entries(&self, phase: &str) -> Result<bool> {
220→        let entries = self.get_phase_entries(phase)?;
221→        Ok(entries.iter().any(|e| e.is_sub_phase()))
222→    }
223→
224→    /// Get all completed sub-phases for a parent phase.
225→    pub fn get_completed_sub_phases(&self, parent_phase: &str) -> Result<Vec<String>> {
226→        let entries = self.get_phase_entries(parent_phase)?;
227→        Ok(entries
228→            .into_iter()
229→            .filter(|e| e.is_sub_phase() && e.status == "completed")
230→            .filter_map(|e| e.sub_phase)
231→            .collect())
232→    }
233→
234→    /// Check if all sub-phases of a parent are complete.
235→    pub fn all_sub_phases_complete(
236→        &self,
237→        parent_phase: &str,
238→        expected_count: usize,
239→    ) -> Result<bool> {
240→        let completed = self.get_completed_sub_phases(parent_phase)?;
241→        Ok(completed.len() >= expected_count)
242→    }
243→
244→    pub fn reset(&self) -> Result<()> {
245→        if self.state_file.exists() {
246→            fs::remove_file(&self.state_file).context("Failed to remove state file")?;
247→        }
248→        Ok(())
249→    }
250→}
