  1→//! DAG scheduler for computing execution order and managing phase states.
  2→//!
  3→//! The scheduler computes execution waves - groups of phases that can run in parallel
  4→//! because their dependencies are satisfied.
  5→
  6→use crate::dag::builder::{DagBuilder, PhaseGraph, PhaseIndex};
  7→use crate::phase::Phase;
  8→use anyhow::{Context, Result};
  9→use serde::{Deserialize, Serialize};
 10→use std::collections::HashSet;
 11→
 12→/// Configuration for the DAG scheduler.
 13→#[derive(Debug, Clone, Serialize, Deserialize)]
 14→pub struct DagConfig {
 15→    /// Maximum phases to run in parallel
 16→    pub max_parallel: usize,
 17→    /// Stop all phases on first failure
 18→    pub fail_fast: bool,
 19→    /// Enable swarm hooks for marked phases
 20→    pub swarm_enabled: bool,
 21→    /// Backend for swarm execution
 22→    pub swarm_backend: SwarmBackend,
 23→    /// Review configuration
 24→    pub review: ReviewConfig,
 25→    /// Enable dynamic decomposition
 26→    pub decomposition_enabled: bool,
 27→    /// Budget percentage threshold for decomposition
 28→    pub decomposition_threshold: u32,
 29→    /// Finding types to always escalate
 30→    pub escalation_types: Vec<String>,
 31→}
 32→
 33→impl Default for DagConfig {
 34→    fn default() -> Self {
 35→        Self {
 36→            max_parallel: 4,
 37→            fail_fast: false,
 38→            swarm_enabled: true,
 39→            swarm_backend: SwarmBackend::Auto,
 40→            review: ReviewConfig::default(),
 41→            decomposition_enabled: true,
 42→            decomposition_threshold: 50,
 43→            escalation_types: Vec::new(),
 44→        }
 45→    }
 46→}
 47→
 48→impl DagConfig {
 49→    /// Create a config with specific max parallelism.
 50→    pub fn with_max_parallel(mut self, max: usize) -> Self {
 51→        self.max_parallel = max;
 52→        self
 53→    }
 54→
 55→    /// Enable or disable fail-fast mode.
 56→    pub fn with_fail_fast(mut self, fail_fast: bool) -> Self {
 57→        self.fail_fast = fail_fast;
 58→        self
 59→    }
 60→
 61→    /// Enable or disable swarm execution.
 62→    pub fn with_swarm_enabled(mut self, enabled: bool) -> Self {
 63→        self.swarm_enabled = enabled;
 64→        self
 65→    }
 66→
 67→    /// Set the swarm backend.
 68→    pub fn with_swarm_backend(mut self, backend: SwarmBackend) -> Self {
 69→        self.swarm_backend = backend;
 70→        self
 71→    }
 72→
 73→    /// Set the review configuration.
 74→    pub fn with_review(mut self, review: ReviewConfig) -> Self {
 75→        self.review = review;
 76→        self
 77→    }
 78→
 79→    /// Enable or disable dynamic decomposition.
 80→    pub fn with_decomposition(mut self, enabled: bool) -> Self {
 81→        self.decomposition_enabled = enabled;
 82→        self
 83→    }
 84→
 85→    /// Set the decomposition budget threshold.
 86→    pub fn with_decomposition_threshold(mut self, threshold: u32) -> Self {
 87→        self.decomposition_threshold = threshold;
 88→        self
 89→    }
 90→
 91→    /// Set the escalation types.
 92→    pub fn with_escalation_types(mut self, types: Vec<String>) -> Self {
 93→        self.escalation_types = types;
 94→        self
 95→    }
 96→}
 97→
 98→/// Backend for swarm execution.
 99→#[derive(Debug, Clone, Copy, PartialEq, Eq, Serialize, Deserialize, Default)]
100→#[serde(rename_all = "snake_case")]
101→pub enum SwarmBackend {
102→    /// Auto-detect the best backend
103→    #[default]
104→    Auto,
105→    /// Run in the same process
106→    InProcess,
107→    /// Use tmux for parallel terminals
108→    Tmux,
109→    /// Use iTerm2 for parallel terminals (macOS)
110→    Iterm2,
111→}
112→
113→/// Review configuration for the DAG scheduler.
114→#[derive(Debug, Clone, Serialize, Deserialize)]
115→pub struct ReviewConfig {
116→    /// Whether reviews are enabled
117→    pub enabled: bool,
118→    /// Default specialists to use if phase has none
119→    pub default_specialists: Vec<String>,
120→    /// Review mode
121→    pub mode: ReviewMode,
122→    /// Max fix attempts for auto mode
123→    pub max_fix_attempts: u32,
124→    /// Arbiter confidence threshold
125→    pub arbiter_confidence: f64,
126→}
127→
128→impl Default for ReviewConfig {
129→    fn default() -> Self {
130→        Self {
131→            enabled: false,
132→            default_specialists: Vec::new(),
133→            mode: ReviewMode::Manual,
134→            max_fix_attempts: 2,
135→            arbiter_confidence: 0.7,
136→        }
137→    }
138→}
139→
140→impl ReviewConfig {
141→    /// Create a config with reviews enabled.
142→    pub fn enabled(specialists: Vec<String>) -> Self {
143→        Self {
144→            enabled: true,
145→            default_specialists: specialists,
146→            ..Default::default()
147→        }
