246→/// The main DAG scheduler.
247→#[derive(Debug)]
248→pub struct DagScheduler {
249→    /// The underlying phase graph
250→    graph: PhaseGraph,
251→    /// Phase nodes with status
252→    nodes: Vec<PhaseNode>,
253→    /// Configuration
254→    config: DagConfig,
255→    /// Set of completed phase indices
256→    completed: HashSet<PhaseIndex>,
257→    /// Set of failed phase indices
258→    failed: HashSet<PhaseIndex>,
259→}
260→
261→impl DagScheduler {
262→    /// Create a DAG scheduler from a list of phases.
263→    pub fn from_phases(phases: &[Phase], config: DagConfig) -> Result<Self> {
264→        let graph = DagBuilder::new(phases.to_vec())
265→            .build()
266→            .context("Failed to build phase dependency graph")?;
267→
268→        let nodes: Vec<PhaseNode> = graph
269→            .phases()
270→            .iter()
271→            .enumerate()
272→            .map(|(i, p)| PhaseNode::new(p.clone(), i))
273→            .collect();
274→
275→        Ok(Self {
276→            graph,
277→            nodes,
278→            config,
279→            completed: HashSet::new(),
280→            failed: HashSet::new(),
281→        })
282→    }
283→
284→    /// Get the number of phases in the DAG.
285→    pub fn phase_count(&self) -> usize {
286→        self.graph.len()
287→    }
288→
289→    /// Get a phase node by its number.
290→    pub fn get_node(&self, number: &str) -> Option<&PhaseNode> {
291→        self.graph.get_index(number).and_then(|i| self.nodes.get(i))
292→    }
293→
294→    /// Get a mutable reference to a phase node.
295→    pub fn get_node_mut(&mut self, number: &str) -> Option<&mut PhaseNode> {
296→        let index = self.graph.get_index(number)?;
297→        self.nodes.get_mut(index)
298→    }
299→
300→    /// Get all phase nodes.
301→    pub fn nodes(&self) -> &[PhaseNode] {
302→        &self.nodes
303→    }
304→
305→    /// Get the configuration.
306→    pub fn config(&self) -> &DagConfig {
307→        &self.config
308→    }
309→
310→    /// Compute execution waves - groups of phases that can run in parallel.
311→    ///
312→    /// Returns a list of waves, where each wave is a list of phase numbers
313→    /// that can be executed in parallel once all previous waves complete.
314→    pub fn compute_waves(&self) -> Vec<Vec<String>> {
315→        let mut waves = Vec::new();
316→        let mut completed: HashSet<PhaseIndex> = HashSet::new();
317→
318→        loop {
319→            // Find all phases whose dependencies are satisfied and not yet completed
320→            let ready: Vec<String> = self
321→                .graph
322→                .phases()
323→                .iter()
324→                .enumerate()
325→                .filter_map(|(i, phase)| {
326→                    if completed.contains(&i) {
327→                        return None;
328→                    }
329→                    if self.graph.dependencies_satisfied(i, &completed) {
330→                        Some(phase.number.clone())
331→                    } else {
332→                        None
333→                    }
334→                })
335→                .collect();
336→
337→            if ready.is_empty() {
338→                break;
339→            }
340→
341→            // Mark these phases as "completed" for the next iteration
342→            for number in &ready {
343→                if let Some(idx) = self.graph.get_index(number) {
344→                    completed.insert(idx);
345→                }
346→            }
347→
348→            waves.push(ready);
349→        }
350→
351→        waves
352→    }
353→
354→    /// Get phases that are ready to run (dependencies satisfied, not started).
355→    pub fn get_ready_phases(&self) -> Vec<&PhaseNode> {
356→        self.nodes
357→            .iter()
358→            .filter(|node| {
359→                if !matches!(node.status, PhaseStatus::Pending) {
360→                    return false;
361→                }
362→                self.graph
363→                    .dependencies_satisfied(node.index, &self.completed)
364→            })
365→            .collect()
366→    }
367→
368→    /// Mark a phase as running.
369→    pub fn mark_running(&mut self, number: &str) {
370→        if let Some(node) = self.get_node_mut(number) {
371→            node.status = PhaseStatus::Running {
372→                started_at_ms: std::time::SystemTime::now()
373→                    .duration_since(std::time::UNIX_EPOCH)
374→                    .unwrap_or_default()
375→                    .as_millis() as u64,
376→            };
377→        }
378→    }
379→
380→    /// Mark a phase as completed.
381→    pub fn mark_completed(&mut self, number: &str, iterations: u32) {
382→        if let Some(idx) = self.graph.get_index(number) {
383→            if let Some(node) = self.nodes.get_mut(idx) {
384→                node.status = PhaseStatus::Completed { iterations };
385→            }
386→            self.completed.insert(idx);
387→        }
388→    }
389→
390→    /// Mark a phase as failed.
391→    pub fn mark_failed(&mut self, number: &str, error: &str) {
392→        if let Some(idx) = self.graph.get_index(number) {
393→            if let Some(node) = self.nodes.get_mut(idx) {
394→                node.status = PhaseStatus::Failed {
395→                    error: error.to_string(),
396→                };
397→            }
398→            self.failed.insert(idx);
399→
400→            // If fail_fast, skip all dependent phases
401→            if self.config.fail_fast {
402→                self.skip_dependents(idx);
403→            }
404→        }
405→    }
406→
407→    /// Mark a phase as skipped.
408→    pub fn mark_skipped(&mut self, number: &str) {
409→        if let Some(idx) = self.graph.get_index(number) {
410→            if let Some(node) = self.nodes.get_mut(idx) {
411→                node.status = PhaseStatus::Skipped;
412→            }
413→            self.failed.insert(idx); // Treat skipped as failed for dependency purposes
414→        }
415→    }
416→
417→    /// Skip all phases that depend on a failed phase.
418→    fn skip_dependents(&mut self, failed_idx: PhaseIndex) {
419→        let dependents: Vec<PhaseIndex> = self.graph.dependents(failed_idx).to_vec();
420→        for dep_idx in dependents {
421→            if let Some(node) = self.nodes.get_mut(dep_idx)
422→                && !node.status.is_terminal()
423→            {
424→                node.status = PhaseStatus::Skipped;
425→                self.failed.insert(dep_idx);
426→                // Recursively skip dependents
427→                self.skip_dependents(dep_idx);
428→            }
429→        }
430→    }
431→
432→    /// Check if all phases are complete (success or failure).
433→    pub fn all_complete(&self) -> bool {
434→        self.nodes.iter().all(|n| n.status.is_terminal())
435→    }
436→
437→    /// Check if all phases completed successfully.
438→    pub fn all_success(&self) -> bool {
439→        self.nodes.iter().all(|n| n.status.is_success())
440→    }
441→
442→    /// Get the number of completed phases.
443→    pub fn completed_count(&self) -> usize {
444→        self.completed.len()
445→    }
446→
447→    /// Get the number of failed phases.
448→    pub fn failed_count(&self) -> usize {
449→        self.failed.len()
450→    }
451→
452→    /// Get completion percentage.
453→    pub fn completion_percentage(&self) -> f64 {
454→        if self.nodes.is_empty() {
455→            return 100.0;
456→        }
457→        let terminal = self.nodes.iter().filter(|n| n.status.is_terminal()).count();
458→        (terminal as f64 / self.nodes.len() as f64) * 100.0
459→    }
460→}
