 56→/// Serve embedded static files or fall back to index.html for SPA routing.
 57→async fn static_handler(req: Request<Body>) -> impl IntoResponse {
 58→    let path = req.uri().path().trim_start_matches('/');
 59→
 60→    // Try to serve the exact file
 61→    if !path.is_empty()
 62→        && let Some(content) = Assets::get(path)
 63→    {
 64→        let mime = mime_guess::from_path(path).first_or_octet_stream();
 65→        match Response::builder()
 66→            .header(header::CONTENT_TYPE, mime.as_ref())
 67→            .body(Body::from(content.data.to_vec()))
 68→        {
 69→            Ok(resp) => return resp.into_response(),
 70→            Err(_) => return StatusCode::INTERNAL_SERVER_ERROR.into_response(),
 71→        }
 72→    }
 73→
 74→    // Fall back to index.html for SPA client-side routing
 75→    match Assets::get("index.html") {
 76→        Some(content) => Html(String::from_utf8_lossy(&content.data).to_string()).into_response(),
 77→        None => (
 78→            StatusCode::NOT_FOUND,
 79→            "Frontend not found. Run 'npm run build' in ui/ directory.",
 80→        )
 81→            .into_response(),
 82→    }
 83→}
