 32→/// Auto-generate spec and phases from an issue description.
 33→/// Writes a design doc to `.forge/spec.md`, then runs `forge generate`.
 34→/// Returns Ok(true) if phases were generated successfully, Ok(false) if generation
 35→/// failed or produced no output (caller should fall back to direct invocation).
 36→pub(crate) async fn auto_generate_phases(
 37→    project_path: &str,
 38→    issue_title: &str,
 39→    issue_description: &str,
 40→) -> Result<bool> {
 41→    // Ensure .forge directory exists
 42→    let forge_dir = std::path::Path::new(project_path).join(".forge");
 43→    if !forge_dir.exists() {
 44→        tokio::fs::create_dir_all(&forge_dir)
 45→            .await
 46→            .context("Failed to create .forge directory")?;
 47→    }
 48→
 49→    // Write a design document from the issue
 50→    let design_content = format!(
 51→        "# {}\n\n## Overview\n\n{}\n\n## Requirements\n\n- Implement the feature described above\n- Ensure all existing tests continue to pass\n- Add tests for new functionality\n",
 52→        issue_title,
 53→        if issue_description.is_empty() {
 54→            "No additional details provided."
 55→        } else {
 56→            issue_description
 57→        }
 58→    );
 59→    let design_path = forge_dir.join("spec.md");
 60→    tokio::fs::write(&design_path, &design_content)
 61→        .await
 62→        .context("Failed to write design document")?;
 63→
 64→    // Run forge generate to create phases.json
 65→    let forge_cmd = std::env::var("FORGE_CMD").unwrap_or_else(|_| "forge".to_string());
 66→    let status = match tokio::process::Command::new(&forge_cmd)
 67→        .arg("generate")
 68→        .current_dir(project_path)
 69→        .stdout(Stdio::piped())
 70→        .stderr(Stdio::piped())
 71→        .status()
 72→        .await
 73→    {
 74→        Ok(s) => s,
 75→        Err(e) => {
 76→            warn!("Failed to spawn '{}': {e}", forge_cmd);
 77→            return Ok(false);
 78→        }
 79→    };
 80→
 81→    if status.success() && has_forge_phases(project_path) {
 82→        Ok(true)
 83→    } else {
 84→        // Generation failed — fall back to simple Claude invocation
