 89→/// Build the command to execute: `forge swarm` if phases exist, otherwise `claude --print`.
 90→pub(crate) fn build_execution_command(
 91→    project_path: &str,
 92→    issue_title: &str,
 93→    issue_description: &str,
 94→) -> tokio::process::Command {
 95→    if has_forge_phases(project_path) {
 96→        // Use forge swarm for full DAG-based parallel execution
 97→        let forge_cmd = std::env::var("FORGE_CMD").unwrap_or_else(|_| "forge".to_string());
 98→        let mut cmd = tokio::process::Command::new(&forge_cmd);
 99→        cmd.arg("swarm")
100→            .arg("--max-parallel")
101→            .arg("4")
102→            .arg("--fail-fast")
103→            .env_remove("CLAUDECODE")
104→            .current_dir(project_path)
105→            .stdout(Stdio::piped())
106→            .stderr(Stdio::piped());
107→        cmd
108→    } else {
109→        // Fallback: direct Claude invocation for simple issues without phases
110→        // Uses stream-json output format for realtime output streaming to the UI
111→        let claude_cmd = std::env::var("CLAUDE_CMD").unwrap_or_else(|_| "claude".to_string());
112→        let prompt = format!(
113→            "Implement the following issue:\n\nTitle: {}\n\nDescription: {}\n",
114→            issue_title, issue_description
115→        );
116→        let mut cmd = tokio::process::Command::new(&claude_cmd);
117→        cmd.arg("--print")
118→            .arg("--verbose")
119→            .arg("--output-format")
120→            .arg("stream-json")
121→            .arg("--dangerously-skip-permissions")
122→            .arg(&prompt)
123→            .env_remove("CLAUDECODE")
124→            .current_dir(project_path)
125→            .stdout(Stdio::piped())
126→            .stderr(Stdio::piped());
127→        cmd
128→    }
129→}
