Command::new(&forge_cmd).args(["swarm", ...])

// AFTER: daemon.start_run() which manages the full agent tree
let run = self.runtime_client
    .start_run(StartRunRequest {
        project: project.id,
        phases: phase_defs,
        policy: project_policy,
    }).await?;
```

