 53→### Keep/Discard/Error match handling
 54→
 55→```
 56→match &exp_result.outcome {
 57→    ExperimentOutcome::Keep => {
 58→        let sha = git.commit(&format!("experiment: {}", exp_result.description))?;
 59→        results.append(ResultRow { status: ExperimentStatus::Keep, .. })?;
 60→        baseline_score = exp_result.score;
 61→        consecutive_failures = 0;
 62→    }
 63→    ExperimentOutcome::Discard => {
 64→        results.append(ResultRow { status: ExperimentStatus::Discard, .. })?;
 65→        git.reset_to_last_keep()?;
 66→        consecutive_failures += 1;
 67→    }
 68→    ExperimentOutcome::Error(msg) => {
 69→        results.append(ResultRow { status: ExperimentStatus::Error, .. })?;
 70→        git.reset_to_last_keep()?;
 71→        consecutive_failures += 1;
 72→    }
 73→}
 74→```
