 79→struct MockGit {
 80→    commits: Mutex<Vec<String>>,
 81→    resets: AtomicU32,
 82→    branch_created: Mutex<Option<String>>,
 83→}
 84→
 85→impl LoopGitOps for MockGit {
 86→    fn commit(&self, message: &str) -> Result<String> {
 87→        let mut commits = self.commits.lock().unwrap();
 88→        let sha = format!("sha{:04}", commits.len());
 89→        commits.push(message.to_string());
 90→        Ok(sha)
 91→    }
 92→    fn reset_to_last_keep(&self) -> Result<()> {
 93→        self.resets.fetch_add(1, Ordering::SeqCst);
 94→        Ok(())
 95→    }
 96→}
